const machines = [
    { id: "MC01", ip: "172.70.66.195" }, 
    { id: "MC02", ip: "172.70.66.184" },
    { id: "MC03", ip: "172.70.66.186" }, 
    { id: "MC04", ip: "172.70.66.188" },
    { id: "MC05", ip: "172.70.66.190" }, 
    { id: "MC06", ip: "172.70.66.194" },
    { id: "MC07", ip: "172.25.72.41" },  
    { id: "MC08", ip: "172.25.72.43" },
    { id: "MC09", ip: "172.25.72.45" },  
    { id: "MC10", ip: "172.25.72.47" }
];

const readBatches = [
    // PV Groups (Berurutan per blok)
    { group: "UP_PV_01_04", start: 3010, count: 4, names: ["UP_PV_01", "UP_PV_02", "UP_PV_03", "UP_PV_04"] },
    { group: "UP_PV_05_08", start: 3160, count: 4, names: ["UP_PV_05", "UP_PV_06", "UP_PV_07", "UP_PV_08"] },
    { group: "DOWN_PV_01_04", start: 3310, count: 4, names: ["DOWN_PV_01", "DOWN_PV_02", "DOWN_PV_03", "DOWN_PV_04"] },
    { group: "DOWN_PV_05_08", start: 3460, count: 4, names: ["DOWN_PV_05", "DOWN_PV_06", "DOWN_PV_07", "DOWN_PV_08"] },
    { group: "UP_SPEED_PV", start: 5790, count: 1, names: ["UP_SPEED_PV"] },
    { group: "DOWN_SPEED_PV", start: 5780, count: 1, names: ["DOWN_SPEED_PV"] },

    // SV Groups (18 Register tunggal karena melompat)
    { group: "UP_SV_01", start: 6101, count: 1, names: ["UP_SV_01"] },
    { group: "UP_SV_02", start: 6201, count: 1, names: ["UP_SV_02"] },
    { group: "UP_SV_03", start: 6301, count: 1, names: ["UP_SV_03"] },
    { group: "UP_SV_04", start: 6401, count: 1, names: ["UP_SV_04"] },
    { group: "UP_SV_05", start: 6501, count: 1, names: ["UP_SV_05"] },
    { group: "UP_SV_06", start: 6601, count: 1, names: ["UP_SV_06"] },
    { group: "UP_SV_07", start: 6701, count: 1, names: ["UP_SV_07"] },
    { group: "UP_SV_08", start: 6801, count: 1, names: ["UP_SV_08"] },
    { group: "DOWN_SV_01", start: 6901, count: 1, names: ["DOWN_SV_01"] },
    { group: "DOWN_SV_02", start: 7001, count: 1, names: ["DOWN_SV_02"] },
    { group: "DOWN_SV_03", start: 7101, count: 1, names: ["DOWN_SV_03"] },
    { group: "DOWN_SV_04", start: 7201, count: 1, names: ["DOWN_SV_04"] },
    { group: "DOWN_SV_05", start: 7301, count: 1, names: ["DOWN_SV_05"] },
    { group: "DOWN_SV_06", start: 7401, count: 1, names: ["DOWN_SV_06"] },
    { group: "DOWN_SV_07", start: 7501, count: 1, names: ["DOWN_SV_07"] },
    { group: "DOWN_SV_08", start: 7601, count: 1, names: ["DOWN_SV_08"] },
    { group: "UP_SPEED_SV", start: 7800, count: 1, names: ["UP_SPEED_SV"] },
    { group: "DOWN_SPEED_SV", start: 7700, count: 1, names: ["DOWN_SPEED_SV"] }
];

const output = [];
for (const mc of machines) {
    for (const batch of readBatches) {
        output.push({
            payload: {
                fc: 3,
                unitid: 1,
                address: batch.start,
                quantity: batch.count
            },
            modbusHost: mc.ip,
            modbusPort: 502,
            machineId: mc.id,
            batchGroup: batch.group,
            batchNames: batch.names
        });
    }
}

msg.payload = output;
return msg;

const rawValues = msg.payload;
const names = msg.batchNames;
const machineId = msg.machineId;

if (!names || !Array.isArray(names)) {
    node.warn(`MC ${machineId || "Unknown"}: batchNames tidak ditemukan (Metadata hilang).`);
    return null;
}

if (!Array.isArray(rawValues)) {
    node.warn(`MC ${machineId || "Unknown"}: Payload dari Modbus bukan array.`);
    return null;
}

function toInt16(val) {
    return val > 32767 ? val - 65536 : val;
}

const result = {};
for (let i = 0; i < names.length; i++) {
    const raw = rawValues[i];
    if (raw === undefined || raw === null) continue;
    result[names[i]] = parseFloat((toInt16(raw) / 10).toFixed(1));
}

msg.payload = {
    machineId: machineId,
    group: msg.batchGroup,
    data: result,
    ts: new Date().toISOString()
};

const currentData = {
    machineId: machineId,
    group: msg.batchGroup,
    data: result,
    ts: new Date().toISOString()
};

// Ambil data database lokal Node-RED (jika belum ada, buat objek kosong)
let machineStore = flow.get("machines_data") || {};
if (!machineStore[machineId]) {
    machineStore[machineId] = {};
}

// Gabungkan data batch yang baru masuk ke dalam database mesin terkait
machineStore[machineId] = Object.assign(machineStore[machineId], result);
machineStore[machineId].last_update = currentData.ts;

// Simpan kembali ke dalam memori flow Node-RED
flow.set("machines_data", machineStore);

// Teruskan data asli ke node berikutnya/debug
msg.payload = currentData;
return msg;
